Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
throughs/flatten.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

var values = require('../sources/values')
var once = require('../sources/once')

//convert a stream of arrays or streams into just a stream.
module.exports = function flatten () {
  return function (read) {
    var _read
    return function (abort, cb) {
      if (abort) { //abort the current stream, and then stream of streams.
        _read ? _read(abort, function(err) {
          <PLACEHOLDER>
        }) : read(abort, cb)
      }
      else if(_read) nextChunk()
      else nextStream()

      function nextChunk () {
        _read(null, function (err, data) {
          if (err) {
            if (err === true) nextStream()
            else read(true, function(abortErr) {
              // TODO: what do we do with the abortErr?
              cb(err)
            })
          }
          else cb(null, data)
        })
      }
      function nextStream () {
        _read = null
        read(null, function (end, stream) {
          if(end)
            return cb(end)
          if(stream && 'object' === typeof stream)
            stream = values(stream)
          else if ('function' !== typeof stream)
            stream = once(stream)
          _read = stream
          nextChunk()
        })
      }
    }
  }
}


In the original code, <PLACEHOLDER> has the value:

-             read(err || abort, cb)
In the mutated code, <PLACEHOLDER> has the value:

+             read(err && abort, cb)


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-e59db35/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the change is from `read(err || abort, cb)` to `read(err && abort, cb)`.

This matters when:
- `err` is falsy (null/undefined) and `abort` is truthy: `err || abort` = `abort` (truthy), but `err && abort` = `err` (falsy/null)

So when aborting and the inner stream's abort callback receives no error (`err` is null/falsy), the original code passes `abort` to the outer `read`, but the mutated code passes `null` (falsy) instead, meaning the outer stream won't be properly aborted.

Let me write a test that:
1. Creates a flatten stream
2. Aborts it while reading from an inner stream
3. Verifies the outer stream receives the abort signal

```typescript
import flatten from "../../../../../../../../../../../subject_repositories/pull-stream/throughs/flatten.js";

describe("flatten abort behavior", () => {
  it("should properly abort the outer stream when aborting with a non-error abort value", (done) => {
    // Track what abort value the outer read receives
    let outerAbortReceived: any = undefined;
    let outerReadCallCount = 0;

    // Create a mock outer read (stream of streams)
    // First call returns an inner stream, subsequent calls handle abort
    const outerRead = (abort: any, cb: Function) => {
      outerReadCallCount++;
      if (abort) {
        outerAbortReceived = abort;
        cb(abort);
        return;
      }
      // Return an inner stream that never ends (hangs)
      const innerRead = (innerAbort: any, innerCb: Function) => {
        if (innerAbort) {
          // Inner stream aborted with no error
          innerCb(null); // err is null/falsy - this is the key case
          return;
        }
        // Never calls back (hangs)
      };
      cb(null, innerRead);
    };

    const flattenThrough = flatten();
    const flatStream = flattenThrough(outerRead);

    // Start reading to get into a state where _read is set
    flatStream(null, (err: any, data: any) => {
      // This callback won't be called since inner stream hangs
    });

    // Give it a tick to set up _read, then abort
    setImmediate(() => {
      const abortValue = new Error("abort signal");

      flatStream(abortValue, (err: any) => {
        // After abort completes, verify the outer stream received the abort signal
        // With original code: read(err || abort, cb) = read(null || abortValue, cb) = read(abortValue, cb)
        // With mutated code: read(err && abort, cb) = read(null && abortValue, cb) = read(null, cb) - outer not aborted!

        try {
          expect(outerAbortReceived).toBe(abortValue);
          done();
        } catch (e) {
          done(e);
        }
      });
    });
  });
});
```
